code_fiber_structure:
// Fonction de composant, balise intrinsèque, symbole Fragment, ou rien
type FiberType =
  | ((props: Record<string, unknown>) => unknown)
  | string
  | symbol
  | null;

interface Fiber {
  type: FiberType;
  props: Record<string, unknown>;
  children: Fiber[];
  path: string[];               // Segments de chemin de la racine à cette fiber
  key?: string | number;        // Clé fournie par l'utilisateur pour une identité stable

  // Bindings d'instance (depuis useAsyncOutput)
  instanceNodes: InstanceNode[];

  // Store (depuis createStore, sérialisable en JSON)
  store?: object;

  // Owner pour le scope réactif (effects, cleanups)
  owner?: Owner | null;
}

